  window.GameDB = {
    meta: _meta,

    // ── MONSTERS ──────────────────────────────────────────────────────────────
    getMonsters: function(filters) {
      let result = _monsters;
      if (!filters) return result;
      if (filters.search) {
        const q = filters.search.toLowerCase();
        result = result.filter(m => m.name.toLowerCase().includes(q) || m.actor_id.includes(q));
      }
      if (filters.tribe) result = result.filter(m => m.tribe === filters.tribe);
      if (filters.grade) result = result.filter(m => m.grade === filters.grade);
      if (filters.group) result = result.filter(m => m.monster_group === filters.group);
      if (filters.catchable) result = result.filter(m => m.catchable);
      return result;
    },

    getMonster: function(id) { return _monsterById[id] || null; },

    // ── CHARACTERS ────────────────────────────────────────────────────────────
    getCharacters: function(filters) {
      let result = _characters;
      if (!filters) return result;
      if (filters.search) {
        const q = filters.search.toLowerCase();
        result = result.filter(c => c.name.toLowerCase().includes(q));
      }
      if (filters.gender) result = result.filter(c => c.gender === filters.gender);
      if (filters.element) result = result.filter(c => c.weapons.some(w => w.element === filters.element));
      if (filters.role) result = result.filter(c => c.weapons.some(w => w.role === filters.role));
      if (filters.special !== undefined) result = result.filter(c => c.special === filters.special);
      return result;
    },

    getCharacter: function(id) { return _characterById[id] || null; },

    // ── COSTUMES ──────────────────────────────────────────────────────────────
    getCostumes: function(charId) {
      if (!charId) return _costumes;
      return _costumes.filter(c => c.char_id === charId);
    },

    // ── PVP ───────────────────────────────────────────────────────────────────
    getPvpRanks: function() { return _pvp_ranks; },
  };

